(*
  Coq port of the finite Schoenfield class-count certificate from
  LeanProofs/A198683Schoenfield.lean.

  The normalized labels below are generated from
  src/Lean/Oeis/A198683/sources/schoenfield-a198683.txt.  For each
  table row, a Count entry introduces the next class label and a Match
  entry reuses the label of the referenced earlier row.
*)

From Stdlib Require Import Arith.PeanoNat.
From Stdlib Require Import Bool.Bool.
From Stdlib Require Import Lists.List.

Import ListNotations.
Set Implicit Arguments.
Open Scope nat_scope.
Set Warnings "-abstract-large-number".

Module LeanProofs.
Module A198683Schoenfield.

Definition normalizedClassCount (labels : list nat) : nat :=
  fold_left Nat.max labels 0.

Fixpoint labelsAreNormalizedFrom (maxSeen : nat) (labels : list nat)
    : bool :=
  match labels with
  | [] => true
  | label :: rest =>
      if Nat.eqb label 0 then
        false
      else if Nat.leb label (S maxSeen) then
        labelsAreNormalizedFrom (Nat.max maxSeen label) rest
      else
        false
  end.

Definition certificateOk (labels : list nat) (rows classes : nat)
    : bool :=
  (Nat.eqb (length labels) rows &&
    Nat.eqb (normalizedClassCount labels) classes) &&
    labelsAreNormalizedFrom 0 labels.

Theorem certificateOk_length_of {labels : list nat} {rows classes : nat}
    (h : certificateOk labels rows classes = true) :
    length labels = rows.
Proof.
  unfold certificateOk in h.
  apply andb_true_iff in h as [h _].
  apply andb_true_iff in h as [h _].
  now apply Nat.eqb_eq in h.
Qed.

Theorem certificateOk_class_count_of {labels : list nat}
    {rows classes : nat}
    (h : certificateOk labels rows classes = true) :
    normalizedClassCount labels = classes.
Proof.
  unfold certificateOk in h.
  apply andb_true_iff in h as [h _].
  apply andb_true_iff in h as [_ h].
  now apply Nat.eqb_eq in h.
Qed.

Theorem certificateOk_normalized_of {labels : list nat} {rows classes : nat}
    (h : certificateOk labels rows classes = true) :
    labelsAreNormalizedFrom 0 labels = true.
Proof.
  unfold certificateOk in h.
  now apply andb_true_iff in h as [_ h].
Qed.

